    if (obj == null || getClass() != obj.getClass()) {
        return false;
    }

    Before beforeAnnotation = (Before) obj;
    BeforeClass beforeClassAnnotation = (BeforeClass) obj;

    return annotation.equals(beforeAnnotation) || annotation.equals(beforeClassAnnotation);
}

